/**
 * Complete element history data for all 118 elements.
 * Each entry has: discoverer, bio, experiment, detailed use, image, fun fact.
 */

export interface ElementHistory {
    discoverer: string;
    discovererBio: string;
    experiment: string;
    detailedUse: string;
    useImage: string;
    funFact: string;
}

