export const ELEMENT_HISTORY: Record<number, ElementHistory> = {
    1: { discoverer: "Henry Cavendish", discovererBio: "English natural philosopher (1731–1810). Famously reclusive, he rarely published his work.", experiment: "In 1766, Cavendish dissolved metals in acid and collected the gas produced. He called it 'inflammable air' because it burned readily. When burned in oxygen it produced water — proving hydrogen is a fundamental element.", detailedUse: "Hydrogen powers fuel cells in cars like the Toyota Mirai, provides thrust for NASA rockets using liquid H₂, and is essential for producing ammonia fertiliser via the Haber process — feeding half the world's population.", useImage: IMG.H, funFact: "The Sun converts 600 million tonnes of hydrogen into helium every second through nuclear fusion!" },
    2: { discoverer: "Pierre Janssen & Joseph Lockyer", discovererBio: "Janssen (French, 1824–1907) and Lockyer (English, 1836–1920) independently observed helium during a solar eclipse in 1868.", experiment: "During the 1868 solar eclipse, they noticed a bright yellow spectral line that didn't match any known element. Lockyer named it 'helium' from Greek 'helios' (sun). It wasn't found on Earth until 1895!", detailedUse: "Helium fills party balloons safely (it won't burn), cools MRI magnets to -269°C, prevents nitrogen narcosis in deep-sea diving tanks, and is used in leak detection for spacecraft.", useImage: IMG.ng, funFact: "Helium makes your voice squeaky because sound travels nearly 3× faster through it than through air!" },
    3: { discoverer: "Johan August Arfwedson", discovererBio: "Swedish chemist (1792–1841) who discovered lithium in petalite while working in Berzelius' lab.", experiment: "In 1817, Arfwedson analysed petalite mineral and found an unknown alkali. He couldn't isolate the pure metal — Humphry Davy achieved that via electrolysis in 1821.", detailedUse: "Lithium powers every smartphone, laptop, and electric vehicle through lithium-ion batteries. Lithium carbonate is also a crucial psychiatric medication for treating bipolar disorder.", useImage: IMG.am, funFact: "Lithium is the lightest metal — so light it can actually float on oil!" },
    4: { discoverer: "Louis Nicolas Vauquelin", discovererBio: "French pharmacist and chemist (1763–1829) who also discovered chromium.", experiment: "In 1798, Vauquelin found beryllium oxide in beryl and emerald gemstones. He initially called it 'glucinium' because the oxide tasted sweet. Wöhler and Bussy isolated the metal in 1828.", detailedUse: "Beryllium is used in the James Webb Space Telescope mirrors, X-ray windows (it's transparent to X-rays), and copper-beryllium alloys make non-sparking tools for explosive environments.", useImage: IMG.ae, funFact: "Emerald gemstones are just beryl crystals with trace chromium — beryllium is hiding inside every emerald!" },
    5: { discoverer: "Joseph Louis Gay-Lussac & Louis Jacques Thénard", discovererBio: "Gay-Lussac (French, 1778–1850) and Thénard (French, 1777–1857) isolated boron by reducing boric acid with potassium.", experiment: "In 1808, they heated boric acid with potassium metal in a copper tube. The reaction produced a dark substance — impure boron. Humphry Davy independently achieved the same result days later.", detailedUse: "Boron makes Pyrex heat-resistant glass for labs and kitchens, is a key ingredient in laundry detergent (borax), and boron carbide is one of the hardest materials known — used in tank armour.", useImage: IMG.ml, funFact: "Boron carbide is so hard it's nicknamed 'black diamond' — it's used in bulletproof vests!" },
    6: { discoverer: "Known since antiquity", discovererBio: "Carbon has been known as charcoal since prehistoric times. Antoine Lavoisier proved diamond is carbon in 1772.", experiment: "Lavoisier focused sunlight through a giant magnifying glass onto a diamond in a sealed jar. It burned completely and produced CO₂ — the same gas from burning charcoal. This proved diamond and graphite are both pure carbon!", detailedUse: "Carbon is the backbone of all life on Earth. As diamond, it's the hardest natural material. As graphite, it fills your pencil. Carbon fibre makes ultra-strong bike frames and aircraft parts. Activated carbon purifies water.", useImage: IMG.C, funFact: "A single carbon atom in your body might have once been part of a dinosaur!" },
    7: { discoverer: "Daniel Rutherford", discovererBio: "Scottish physician and chemist (1749–1819), uncle of Sir Walter Scott.", experiment: "In 1772, Rutherford removed oxygen and CO₂ from air by burning candles and absorbing gases. What remained wouldn't support life or combustion — 'noxious air.' This was nitrogen, 78% of our atmosphere.", detailedUse: "Nitrogen makes up 78% of every breath. It's critical for fertilisers (ammonia), explosives (TNT), and liquid nitrogen (-196°C) flash-freezes food, preserves biological samples, and creates concert smoke effects.", useImage: IMG.nm, funFact: "If you removed all nitrogen from the atmosphere, the sky would appear completely black!" },
    8: { discoverer: "Joseph Priestley & Carl Wilhelm Scheele", discovererBio: "Priestley (English, 1733–1804) isolated the gas in 1774. Scheele (Swedish, 1742–1786) discovered it independently but published later.", experiment: "Priestley focused sunlight onto mercuric oxide and collected the gas released. A candle burned brighter and a mouse lived longer in it. He called it 'dephlogisticated air.' Lavoisier later named it oxygen.", detailedUse: "Oxygen is essential for breathing — cells convert food to energy using it. Hospitals use oxygen tanks for patients. Steel mills blast pure oxygen into molten iron. Liquid oxygen (LOX) is a key rocket propellant.", useImage: IMG.O, funFact: "About 65% of your body mass is oxygen — mostly because water (H₂O) is 89% oxygen by mass!" },
    9: { discoverer: "Henri Moissan", discovererBio: "French chemist (1852–1907) who won the Nobel Prize in 1906 for isolating fluorine after many chemists were injured trying.", experiment: "In 1886, Moissan electrolysed a solution of potassium hydrogen fluoride in liquid hydrogen fluoride at -23°C using platinum electrodes. Several previous chemists had been poisoned or killed attempting this — Moissan himself suffered health damage.", detailedUse: "Fluorine is in toothpaste (fluoride strengthens enamel), non-stick Teflon coatings on pans, and refrigerants. Fluorine compounds are used in uranium enrichment for nuclear fuel and in many pharmaceutical drugs.", useImage: IMG.ha, funFact: "Fluorine is the most reactive element in the entire periodic table — it reacts with almost everything, even glass!" },
    10: { discoverer: "William Ramsay & Morris Travers", discovererBio: "Ramsay (Scottish, 1852–1916) won the Nobel Prize in 1904 for discovering the noble gases.", experiment: "In 1898, they cooled air until it liquefied, then slowly warmed it. After removing nitrogen, oxygen, and argon, they captured a glowing reddish-orange gas — neon, from Greek 'neos' meaning 'new.'", detailedUse: "Neon's famous use is in neon signs — electricity through neon gas produces a distinctive red-orange glow. It's also used in high-voltage indicators, helium-neon lasers, and cryogenic refrigeration.", useImage: IMG.ng, funFact: "Despite 'neon signs' coming in every colour, only the red-orange ones actually contain neon — other colours use different gases!" },
    11: { discoverer: "Humphry Davy", discovererBio: "English chemist (1778–1829), one of the greatest experimentalists. He also discovered potassium, calcium, and more.", experiment: "In 1807, Davy passed electric current through molten caustic soda (NaOH). Shiny globules of a new metal appeared at the electrode — some burst into flame on contact with water! He had isolated sodium.", detailedUse: "Sodium is vital for nerve signalling in your body. As NaCl (table salt), it flavours food worldwide. Sodium vapour lamps create the orange glow of street lights. Liquid sodium cools some nuclear reactors.", useImage: IMG.am, funFact: "Pure sodium metal explodes violently when dropped in water! 💥" },
    12: { discoverer: "Joseph Black", discovererBio: "Scottish-Irish chemist and physician (1728–1799) who recognised magnesium as a distinct element.", experiment: "In 1755, Black distinguished magnesia (MgO) from lime (CaO) by showing they produced different salts. Humphry Davy isolated the pure metal in 1808 by electrolysing a mixture of magnesia and mercuric oxide.", detailedUse: "Magnesium makes fireworks sparkle bright white. Magnesium alloys are ultra-lightweight — used in laptops, camera bodies, and racing car wheels. It's essential for human health: over 300 enzyme reactions need Mg²⁺.", useImage: IMG.ae, funFact: "Magnesium burns so brightly it was once used in camera flash powder — early photographers literally set it on fire!" },
    13: { discoverer: "Hans Christian Ørsted", discovererBio: "Danish physicist and chemist (1777–1851), famous for discovering electromagnetism.", experiment: "In 1825, Ørsted produced impure aluminium by reacting aluminium chloride with potassium amalgam. Friedrich Wöhler refined the process in 1827. Until the Hall-Héroult electrolysis process (1886), aluminium was more expensive than gold!", detailedUse: "Aluminium makes soda cans, kitchen foil, and aircraft bodies (Boeing 747 uses ~75 tonnes). It's the most abundant metal in Earth's crust but never found pure — it must be extracted from bauxite ore.", useImage: IMG.pt, funFact: "Napoleon III served his most honoured guests with aluminium cutlery — lesser guests got gold!" },
    14: { discoverer: "Jöns Jacob Berzelius", discovererBio: "Swedish chemist (1779–1848), founder of modern chemistry who invented chemical notation like H₂O.", experiment: "In 1824, Berzelius heated potassium fluorosilicate with potassium metal and obtained a brown amorphous powder — impure silicon. He cleaned it by repeated washing with water.", detailedUse: "Silicon is the foundation of the digital age — every CPU, GPU, and smartphone chip is made from ultra-pure silicon wafers. Solar panels convert sunlight to electricity using silicon. Sand (SiO₂) is melted to make glass.", useImage: IMG.Si, funFact: "A single modern CPU chip contains over 100 billion silicon transistors!" },
    15: { discoverer: "Hennig Brand", discovererBio: "German alchemist (1630–1692) who was searching for the Philosopher's Stone to turn lead into gold.", experiment: "In 1669, Brand boiled down 60 buckets of urine (!), heating the residue until it glowed. The resulting waxy white substance glowed in the dark — he had discovered phosphorus, from Greek 'phosphoros' (light-bearer).", detailedUse: "Phosphorus is in matchstick heads (red phosphorus), the DNA backbone of every living cell, fertilisers (phosphate), and LED screens. Your bones and teeth are calcium phosphate compounds.", useImage: IMG.nm, funFact: "Phosphorus was discovered from URINE — Brand collected 5,500 litres of it from local taverns! 🤢" },
    16: { discoverer: "Known since antiquity", discovererBio: "Sulfur was known to ancient civilisations. Called 'brimstone' in the Bible, it was associated with volcanic activity.", experiment: "Ancient Chinese used sulfur in gunpowder around the 9th century. Antoine Lavoisier proved it was an element in 1777 by showing it couldn't be broken down into simpler substances through any chemical reaction.", detailedUse: "Sulfur vulcanises rubber (making tyres flexible), is essential for sulfuric acid (the most-produced industrial chemical), is in gunpowder, and is a key nutrient in proteins — your hair contains sulfur!", useImage: IMG.nm, funFact: "Sulfur burns with a beautiful blue flame — volcanic sulfur fires at Indonesia's Kawah Ijen look otherworldly!" },
    17: { discoverer: "Carl Wilhelm Scheele", discovererBio: "Swedish-German chemist (1742–1786). Discovered many elements but rarely got credit due to late publishing.", experiment: "In 1774, Scheele heated hydrochloric acid with manganese dioxide, producing a pungent yellow-green gas. Humphry Davy proved it was an element in 1810 and named it 'chlorine' from Greek 'chloros' (green-yellow).", detailedUse: "Chlorine saves millions of lives through water purification — killing deadly bacteria in drinking water. It's used to make PVC pipes, bleach, disinfectants, and pharmaceuticals. Swimming pools use chlorine compounds.", useImage: IMG.ha, funFact: "Chlorine was used as a chemical weapon in WWI, but today it saves far more lives through clean water!" },
    18: { discoverer: "Lord Rayleigh & William Ramsay", discovererBio: "Rayleigh (English, 1842–1919) noticed atmospheric nitrogen was heavier than chemical nitrogen. Ramsay (Scottish, 1852–1916) identified the extra gas.", experiment: "In 1894, Rayleigh found that nitrogen from air was denser than nitrogen from chemicals. Ramsay removed all known gases from air and found a leftover — a completely inert gas. They named it argon from Greek 'argos' (lazy).", detailedUse: "Argon fills light bulbs to prevent tungsten filaments from burning. It shields welds from oxygen contamination (TIG/MIG welding). It's used in double-glazed windows for insulation and in lab gloveboxes.", useImage: IMG.ng, funFact: "Argon makes up nearly 1% of our atmosphere — every breath you take contains about 10 mL of argon!" },
    19: { discoverer: "Humphry Davy", discovererBio: "English chemist (1778–1829) who isolated potassium just days before sodium using the same electrolysis technique.", experiment: "In 1807, Davy passed electricity through molten potash (KOH). Tiny metallic globules formed and immediately caught fire with a lavender flame. He wrote in his notebook that he 'danced around the lab with joy.'", detailedUse: "Potassium is essential for nerve and muscle function — bananas are famously rich in it. Potassium fertilisers (potash) are vital for crop growth. Potassium nitrate is used in fireworks and food preservation.", useImage: IMG.am, funFact: "Humphry Davy was so excited when he isolated potassium that he literally danced around his laboratory!" },
    20: { discoverer: "Humphry Davy", discovererBio: "English chemist (1778–1829) who isolated calcium through electrolysis of a lime-mercury mixture in 1808.", experiment: "In 1808, Davy electrolysed a mixture of lime (CaO) and mercuric oxide, producing a calcium-mercury amalgam. He then distilled away the mercury to obtain pure calcium metal.", detailedUse: "Calcium makes bones and teeth strong (99% of your body's calcium is there). Calcium carbonate (limestone) makes cement and concrete. Calcium chloride de-ices roads in winter. Chalk is calcium carbonate too!", useImage: IMG.ae, funFact: "Your body contains about 1 kg of calcium — enough to make a small piece of chalk!" },
    21: { discoverer: "Lars Fredrik Nilson", discovererBio: "Swedish chemist (1840–1899) who found scandium in rare minerals from Scandinavia.", experiment: "In 1879, Nilson was analysing the minerals euxenite and gadolinite when he found a new oxide. Mendeleev had predicted this element ('eka-boron') 10 years earlier, validating his periodic table!", detailedUse: "Scandium-aluminium alloys make ultra-lightweight bicycle frames and baseball bats. It's used in high-intensity stadium lights and Russian MiG fighter jet components. Very rare and expensive.", useImage: IMG.tm, funFact: "Mendeleev predicted scandium's existence and properties 10 years before it was found — proving his periodic table worked!" },
    22: { discoverer: "William Gregor", discovererBio: "English clergyman and mineralogist (1761–1817) who found titanium in black sand while studying minerals as a hobby.", experiment: "In 1791, Gregor found a magnetic black sand in a stream in Cornwall. Analysing it, he discovered an unknown metal oxide. Martin Klaproth independently found it in 1795 and named it 'titanium' after the Greek Titans.", detailedUse: "Titanium is as strong as steel but 45% lighter. It's used in jet engines, hip and knee replacements (it's biocompatible), spacecraft, and high-end bicycle frames. TiO₂ makes white paint, sunscreen, and toothpaste white.", useImage: IMG.tm, funFact: "The SR-71 Blackbird spy plane was made of 85% titanium — the US secretly bought it from the Soviet Union during the Cold War!" },
    23: { discoverer: "Andrés Manuel del Río", discovererBio: "Spanish-Mexican mineralogist (1764–1849) who first found vanadium in 1801 but was convinced he was wrong.", experiment: "In 1801, del Río found a new element in brown lead ore. He named it 'erythronium' because its salts turned red when heated. Sadly, French chemists told him it was just chromium. Nils Sefström rediscovered it in 1830.", detailedUse: "Vanadium strengthens steel alloys for tools, springs, and car parts. Vanadium redox batteries are promising for large-scale energy storage. Ford's Model T used vanadium steel, making it lighter and stronger.", useImage: IMG.tm, funFact: "Henry Ford chose vanadium steel for the Model T after seeing a French racing car crash — the vanadium steel barely dented!" },
    24: { discoverer: "Louis Nicolas Vauquelin", discovererBio: "French pharmacist (1763–1829), the same chemist who discovered beryllium.", experiment: "In 1797, Vauquelin analysed a bright red Siberian mineral (crocoite, PbCrO₄). By treating it with hydrochloric acid, he obtained a beautiful green oxide of a new element — 'chromium' from Greek 'chroma' (colour).", detailedUse: "Chromium makes stainless steel resist rust (cutlery, sinks, surgical tools). Chrome plating creates shiny car bumpers. Chromium compounds make rubies red and emeralds green. Used in leather tanning.", useImage: IMG.tm, funFact: "Both rubies (red) and emeralds (green) get their colour from chromium atoms — same element, completely different colours!" },
    25: { discoverer: "Johan Gottlieb Gahn", discovererBio: "Swedish chemist and mineralogist (1745–1818) who isolated manganese by reducing its oxide with carbon.", experiment: "In 1774, Gahn heated manganese dioxide (pyrolusite) with charcoal in a furnace. The carbon stripped away the oxygen, leaving behind a hard, brittle, silvery metal — pure manganese.", detailedUse: "Manganese is essential for steel production — it removes sulfur and oxygen impurities. Alkaline batteries use MnO₂. It's a trace element your body needs for bone formation and metabolism.", useImage: IMG.tm, funFact: "90% of all manganese produced goes into steel-making — without it, steel would be too brittle to use!" },
    26: { discoverer: "Known since antiquity", discovererBio: "Iron smelting began around 1500 BC with the Hittites of ancient Turkey, starting the Iron Age.", experiment: "Ancient smelters heated iron ore with charcoal in clay furnaces. Carbon removed oxygen from the ore. Abraham Darby (1678–1717) revolutionised production using coke-fired blast furnaces.", detailedUse: "Iron is the most-used metal on Earth. Steel (iron + carbon) builds skyscrapers, bridges, cars, and ships. In your body, iron sits in haemoglobin — it's what makes blood red and carries oxygen to every cell.", useImage: IMG.Fe, funFact: "Earth's core is mostly iron — about 32% of Earth's total mass! That's what creates our magnetic field." },
    27: { discoverer: "Georg Brandt", discovererBio: "Swedish chemist and mineralogist (1694–1768), the first person to discover a metal unknown to ancient civilisations.", experiment: "In 1735, Brandt analysed a blue mineral that miners called 'kobold' (German for goblin, as it was troublesome to smelt). He showed the blue colour came from a new metal, not bismuth or copper as believed.", detailedUse: "Cobalt makes brilliant blue glass and pottery (used since ancient Egypt). It's critical for lithium-ion battery cathodes (your phone needs cobalt!). Cobalt-60 is used in cancer radiotherapy and food sterilisation.", useImage: IMG.tm, funFact: "The word 'cobalt' comes from 'kobold' (goblin) — German miners thought goblins had cursed the troublesome ore!" },
    28: { discoverer: "Axel Fredrik Cronstedt", discovererBio: "Swedish mineralogist (1722–1765) who also developed the modern classification of minerals.", experiment: "In 1751, Cronstedt was studying a green mineral from a cobalt mine. He extracted a white metal that was attracted to magnets but wasn't iron — he named it 'nickel' after 'Kupfernickel' (devil's copper).", detailedUse: "Nickel is in stainless steel (cutlery, appliances), coins (US nickel is 75% copper, 25% nickel), rechargeable NiMH batteries, and guitar strings. Nickel plating protects against corrosion.", useImage: IMG.tm, funFact: "The US 'nickel' coin actually contains more copper than nickel — it's 75% copper!" },
    29: { discoverer: "Known since antiquity", discovererBio: "Copper has been used for over 10,000 years. The name comes from Cyprus, where Romans mined it extensively.", experiment: "Ancient peoples hammered copper nuggets into tools. Around 5000 BC, Middle Eastern peoples learned heating malachite with charcoal reduced it to copper. Mixing with tin around 3300 BC created bronze — starting the Bronze Age.", detailedUse: "Copper's excellent conductivity makes it essential for all electrical wiring. Copper pipes carry water in most buildings. The Statue of Liberty is 80 tonnes of copper. Copper is naturally antibacterial.", useImage: IMG.Cu, funFact: "The average home contains about 180 kg of copper — mostly hidden as electrical wiring inside your walls!" },
    30: { discoverer: "Andreas Sigismund Marggraf", discovererBio: "German chemist (1709–1782) who first isolated zinc metal by heating calamine ore with carbon.", experiment: "In 1746, Marggraf heated calamine (zinc carbonate) with charcoal in a closed vessel and condensed the zinc vapour. While zinc had been used in brass for millennia, this was the first isolation in Europe.", detailedUse: "Zinc galvanises steel to prevent rust (lamp posts, car bodies). Zinc oxide is in sunscreen and calamine lotion. Zinc-carbon batteries power billions of devices. Your body needs zinc for immune function.", useImage: IMG.tm, funFact: "Pennies minted after 1982 are actually 97.5% zinc with a thin copper coating!" },
    31: { discoverer: "Paul Emile Lecoq de Boisbaudran", discovererBio: "French chemist (1838–1912) who used spectroscopy to discover new elements.", experiment: "In 1875, de Boisbaudran examined zinc ore with a spectroscope and found two new violet spectral lines. He isolated a silvery metal and named it 'gallium' after Gallia (Latin for France). Mendeleev had predicted it ('eka-aluminium')!", detailedUse: "Gallium arsenide makes LEDs, laser diodes, and solar cells on spacecraft. Gallium metal melts at just 29.8°C — it literally melts in your hand! It's used in thermometers and semiconductor chips.", useImage: IMG.pt, funFact: "Gallium melts in your hand at 29.8°C! There's a trick where a gallium spoon dissolves in hot tea ☕" },
    32: { discoverer: "Clemens Winkler", discovererBio: "German chemist (1838–1904) who found germanium in a rare silver mineral — validating Mendeleev's predictions.", experiment: "In 1886, Winkler analysed a new mineral called argyrodite. He found it contained a new element whose properties perfectly matched Mendeleev's prediction of 'eka-silicon' from 15 years earlier!", detailedUse: "Germanium is used in fibre optic cables (infrared-transparent), infrared lenses for thermal cameras and night vision, and some transistors. It was the first semiconductor used in early transistors before silicon took over.", useImage: IMG.ml, funFact: "The first ever transistor, invented in 1947 at Bell Labs, used germanium — kickstarting the digital revolution!" },
    33: { discoverer: "Known since antiquity", discovererBio: "Arsenic compounds were known to ancient Greeks and Romans. Albertus Magnus is credited with isolating the element around 1250 AD.", experiment: "Around 1250, Albertus Magnus heated soap together with arsenic trisulfide (orpiment). The arsenic sublimed and condensed as a grey metallic deposit. For centuries, arsenic was infamously used as a poison.", detailedUse: "Arsenic treats certain types of leukaemia (arsenic trioxide). Gallium arsenide (GaAs) semiconductors are in phones and solar cells. Wood preservatives (CCA) used arsenic compounds. Also used in lead-acid batteries.", useImage: IMG.ml, funFact: "Arsenic was called 'inheritance powder' in Renaissance Italy — it was odourless, tasteless, and symptoms mimicked natural illness!" },
    34: { discoverer: "Jöns Jacob Berzelius", discovererBio: "Swedish chemist (1779–1848) who also discovered silicon, cerium, and thorium.", experiment: "In 1817, Berzelius was investigating a sulfuric acid factory residue. He found a substance that smelled of horseradish and initially thought it was tellurium. Further analysis revealed a new element — selenium, named after Selene (Greek moon goddess).", detailedUse: "Selenium is critical for solar cells (thin-film CdTe panels). Anti-dandruff shampoo uses selenium sulfide. It's an essential trace nutrient for humans. Selenium is used in photocopiers and glass-making.", useImage: IMG.nm, funFact: "Selenium was named after the Moon (Selene) because it was found alongside tellurium, named after the Earth (Tellus)!" },
    35: { discoverer: "Antoine Jérôme Balard", discovererBio: "French chemist (1802–1876) who was a pharmacy student when he discovered bromine in seaweed ash.", experiment: "In 1826, Balard treated seaweed ash with chlorine and noticed a dark, foul-smelling liquid separating out. He named it 'bromine' from Greek 'bromos' (stench). Carl Löwig had independently found it, but published later.", detailedUse: "Bromine compounds are flame retardants in electronics and furniture. Silver bromide was essential for photographic film. Brominated vegetable oil stabilises citrus-flavoured drinks. Used in water treatment.", useImage: IMG.ha, funFact: "Bromine is one of only two elements that are liquid at room temperature — the other is mercury!" },
    36: { discoverer: "William Ramsay & Morris Travers", discovererBio: "Ramsay (Scottish, 1852–1916) and Travers (English, 1872–1961) discovered krypton just weeks after finding neon.", experiment: "In 1898, they evaporated nearly all components of liquid air and examined the residue spectroscopically. They found a new gas with a bright green and yellow spectral signature — 'krypton' from Greek 'kryptos' (hidden).", detailedUse: "Krypton is used in high-performance flash photography, energy-efficient fluorescent lamps, and was once used to define the metre (1 metre = 1,650,763.73 wavelengths of krypton-86 orange light).", useImage: IMG.ng, funFact: "Superman's home planet is named after this real element — but actual krypton is a harmless, colourless gas!" },
    37: { discoverer: "Robert Bunsen & Gustav Kirchhoff", discovererBio: "Bunsen (German, 1811–1899) and Kirchhoff (German, 1824–1887) pioneered spectroscopy together.", experiment: "In 1861, they evaporated mineral water and examined its flame spectrum. Two new red spectral lines appeared that matched no known element — rubidium, from Latin 'rubidus' (deep red).", detailedUse: "Rubidium is used in atomic clocks (GPS satellites need ultra-precise timing), photoelectric cells, and medical brain-tumour imaging. Rubidium vapour cells create ultra-sensitive magnetometers.", useImage: IMG.am, funFact: "GPS satellites use rubidium atomic clocks — without them, your phone's location would drift by 10 km per day!" },
    38: { discoverer: "Adair Crawford & William Cruickshank", discovererBio: "Crawford (Irish, 1748–1795) was a physician who distinguished strontium from barium in 1790.", experiment: "In 1790, Crawford noticed that a mineral from Strontian, Scotland, produced a red flame unlike barium's green. Humphry Davy isolated the metal by electrolysis in 1808.", detailedUse: "Strontium compounds create the brilliant red colour in fireworks and flares. Strontium-90 powers thermoelectric generators. Strontium ranelate treats osteoporosis. Glow-in-the-dark paint uses strontium aluminate.", useImage: IMG.ae, funFact: "The brilliant red explosions in fireworks displays are almost always created by strontium compounds!" },
    39: { discoverer: "Johan Gadolin", discovererBio: "Finnish chemist (1760–1852), the first to isolate a rare earth element—from which yttrium takes its name.", experiment: "In 1794, Gadolin analysed a black mineral found near Ytterby, Sweden. He extracted an unknown oxide he called 'yttria.' Yttrium metal was first isolated by Friedrich Wöhler in 1828.", detailedUse: "Yttrium makes red phosphors in TV and LED screens. YAG lasers (yttrium aluminium garnet) are used in surgery and metal cutting. Yttrium stabilises zirconia for jet engine thermal barriers.", useImage: IMG.tm, funFact: "Four elements are named after the tiny Swedish village of Ytterby (pop ~2000): yttrium, erbium, terbium, and ytterbium!" },
    40: { discoverer: "Martin Heinrich Klaproth", discovererBio: "German chemist (1743–1817) who also discovered uranium and named both elements.", experiment: "In 1789, Klaproth analysed the gemstone hyacinth (zircon) and found a new oxide. He named it zirconium after the mineral. The pure metal wasn't isolated until 1914.", detailedUse: "Zirconium cladding protects nuclear fuel rods (it barely absorbs neutrons). Cubic zirconia is a popular diamond substitute in jewellery. Zirconium is used in surgical instruments and ceramic dental crowns.", useImage: IMG.tm, funFact: "Cubic zirconia looks so much like diamond that even experts sometimes need instruments to tell them apart!" },
    41: { discoverer: "Charles Hatchett", discovererBio: "English chemist (1765–1847) who found niobium in a mineral sent to England from Massachusetts, USA.", experiment: "In 1801, Hatchett analysed a mineral in the British Museum labelled 'columbite.' He found a new element and named it 'columbium.' It was later renamed 'niobium' after Niobe, daughter of Tantalus in Greek mythology.", detailedUse: "Niobium alloys make superconducting magnets for MRI machines and particle accelerators (CERN's LHC). Niobium steel strengthens gas pipelines and car bodies. It's used in hypoallergenic jewellery and body piercings.", useImage: IMG.tm, funFact: "CERN's Large Hadron Collider uses over 1,200 tonnes of niobium-titanium superconducting cable!" },
    42: { discoverer: "Carl Wilhelm Scheele", discovererBio: "Swedish chemist (1742–1786), the prolific but unlucky discoverer (he identified oxygen before Priestley but published later).", experiment: "In 1778, Scheele recognised that molybdenite (MoS₂) was not a lead ore as believed, but contained a new element. Peter Jacob Hjelm isolated the metal in 1781 by reducing the oxide with carbon.", detailedUse: "Molybdenum strengthens steel alloys for armour plating, drilling equipment, and high-temperature applications. MoS₂ is an excellent lubricant. Molybdenum is an essential trace nutrient for plants and animals.", useImage: IMG.tm, funFact: "Molybdenum has the 6th highest melting point of any element — 2,623°C! Perfect for extreme heat." },
    43: { discoverer: "Carlo Perrier & Emilio Segrè", discovererBio: "Perrier (Italian, 1886–1948) and Segrè (Italian-American, 1905–1989, Nobel laureate) created the first artificial element.", experiment: "In 1937, they analysed a molybdenum foil that had been bombarded with deuterons in a cyclotron at Berkeley. They found radioactive atoms of element 43 — technetium, from Greek 'technetos' (artificial).", detailedUse: "Technetium-99m is the most widely used radioactive tracer in medical imaging — over 30 million diagnostic scans per year. It helps doctors see blood flow, detect cancer, and diagnose bone disorders.", useImage: IMG.tm, funFact: "Technetium was the first artificially produced element — all technetium on Earth has decayed long ago!" },
    44: { discoverer: "Karl Karlovich Klaus", discovererBio: "Baltic German chemist (1796–1864) working at Kazan University in Russia.", experiment: "In 1844, Klaus analysed platinum ore residues and found a new metal alongside osmium and iridium. He named it 'ruthenium' after Ruthenia, the Latin name for Russia.", detailedUse: "Ruthenium hardens platinum and palladium alloys for electrical contacts that resist wear. It's used in catalysts for chemical processes, chip resistors in electronics, and experimental solar cells.", useImage: IMG.tm, funFact: "Ruthenium is one of the rarest elements on Earth — annual production is only about 20 tonnes worldwide!" },
    45: { discoverer: "William Hyde Wollaston", discovererBio: "English chemist (1766–1828) who made a fortune from his secret method of making malleable platinum.", experiment: "In 1803, Wollaston dissolved crude platinum in aqua regia and found a rose-red solution that yielded a new metal. He named it rhodium from Greek 'rhodon' (rose) due to the colour of its compounds.", detailedUse: "Rhodium in catalytic converters turns toxic car exhaust into harmless gases. It's used in searchlight reflectors, jewellery plating (white gold), and high-temperature thermocouples. Extremely rare and precious.", useImage: IMG.tm, funFact: "Rhodium is the most expensive precious metal — at times costing over $20,000 per ounce, more than gold!" },
    46: { discoverer: "William Hyde Wollaston", discovererBio: "English chemist (1766–1828) who discovered both palladium and rhodium from platinum ore.", experiment: "In 1803, Wollaston dissolved platinum in aqua regia and precipitated out platinum, leaving a residue. He treated this with mercury cyanide and obtained a new silver-white metal — palladium, named after asteroid Pallas.", detailedUse: "Palladium is the key metal in automobile catalytic converters (reducing pollution). It's used in hydrogen purification, electronics (multilayer ceramic capacitors), and dentistry (dental fillings and crowns).", useImage: IMG.tm, funFact: "Wollaston anonymously sold palladium through a London shop to prove it was real after sceptics denied its existence!" },
    47: { discoverer: "Known since antiquity", discovererBio: "Silver has been mined since roughly 5000 BC. Ancient Anatolians separated silver from lead ore using cupellation.", experiment: "Ancient metallurgists heated lead-silver ore in shallow clay vessels with air blasts. Lead oxidised and was absorbed by the clay; pure silver remained. This cupellation technique, perfected by Egyptians, is still used.", detailedUse: "Silver has the highest electrical and thermal conductivity of any element. It's used in mirrors, photography (silver halide), antibacterial medical bandages, water purification, and electronics soldering.", useImage: IMG.tm, funFact: "A single ounce of silver can be drawn into a wire over 8,000 feet (2.4 km) long!" },
    48: { discoverer: "Friedrich Stromeyer", discovererBio: "German chemist (1776–1835) who found cadmium as an impurity in zinc carbonate.", experiment: "In 1817, Stromeyer noticed that zinc carbonate samples from a pharmacy turned yellow when heated (pure ZnCO₃ should stay white). He isolated a new metal from the impurity — cadmium, named from Latin 'cadmia' (calamine).", detailedUse: "Cadmium is used in rechargeable NiCd batteries, brilliant yellow/red pigments for artists, and cadmium telluride solar cells. Cadmium plating protects steel from corrosion in marine environments.", useImage: IMG.tm, funFact: "Cadmium yellow paint was a favourite of impressionist painters — Claude Monet and Van Gogh both used it extensively!" },
    49: { discoverer: "Ferdinand Reich & Hieronymus Richter", discovererBio: "Reich (German, 1799–1882) and Richter (German, 1824–1898) found indium spectroscopically in zinc ore.", experiment: "In 1863, Reich was looking for thallium in zinc ore using spectroscopy. He was colour-blind, so Richter examined the flame and found a brilliant indigo line — a new element! Named 'indium' after indigo.", detailedUse: "Indium tin oxide (ITO) coats every touchscreen — phone, tablet, and laptop. It's transparent and electrically conductive. Indium seals cryogenic equipment and is used in some solders and semiconductors.", useImage: IMG.pt, funFact: "Every time you swipe your phone screen, you're touching a thin layer of indium tin oxide!" },
    50: { discoverer: "Known since antiquity", discovererBio: "Tin has been used since about 3500 BC. Ancient Britons traded tin with Phoenician merchants.", experiment: "Bronze Age civilisations discovered that mixing tin with copper created bronze — harder than either metal alone. This transformative discovery around 3300 BC started the Bronze Age, one of humanity's great leaps forward.", detailedUse: "Tin coats steel cans ('tin cans') to prevent rust. Tin-lead solder joins electronic components. Bronze (copper-tin alloy) makes bells, cymbals, and statues. Tin compounds coat glass for smartphone screens.", useImage: IMG.pt, funFact: "'Tin cans' are actually 99% steel with just a thin tin coating — the name stuck from the 1800s!" },
    51: { discoverer: "Known since antiquity", discovererBio: "Antimony has been used since ancient Egypt for cosmetics (kohl eyeliner). Nicolas Lémery wrote the first chemistry textbook about it in 1707.", experiment: "Ancient Egyptians used stibnite (Sb₂S₃) as black eye makeup. Basil Valentine (15th century) described antimony's medicinal uses. Lémery's 1707 'Treatise on Antimony' was the first chemistry textbook about a single element.", detailedUse: "Antimony makes flame retardants for children's clothing and furniture. Lead-antimony alloy strengthens car batteries. Antimony trioxide is a catalyst for PET plastic production (your water bottles).", useImage: IMG.ml, funFact: "Cleopatra used antimony-based kohl as eye makeup — the same element that now makes your clothes flame-resistant!" },
    52: { discoverer: "Franz-Joseph Müller von Reichenstein", discovererBio: "Austrian mineralogist (1742–1825) who found tellurium in gold ore in Transylvania.", experiment: "In 1783, Müller found a semi-metallic substance in gold ore that wasn't antimony or bismuth. Martin Klaproth confirmed it was a new element in 1798 and named it 'tellurium' from Latin 'tellus' (earth).", detailedUse: "Cadmium telluride makes efficient thin-film solar panels. Tellurium improves steel machining and is used in thermoelectric cooling devices. Bismuth telluride chips keep your car's seat cooler or mini-fridges cold.", useImage: IMG.ml, funFact: "Tellurium is one of the rarest elements in Earth's crust — rarer than gold and platinum!" },
    53: { discoverer: "Bernard Courtois", discovererBio: "French chemist (1777–1838) who accidentally discovered iodine while making gunpowder components during Napoleon's wars.", experiment: "In 1811, Courtois was extracting sodium compounds from seaweed ash for gunpowder. He added too much sulfuric acid, and a violet vapour rose up, condensing into dark, shiny crystals — iodine, from Greek 'iodes' (violet).", detailedUse: "Iodine is essential for thyroid hormones (regulating metabolism). Iodised salt prevents goitre (thyroid swelling). Iodine solution (Betadine) disinfects wounds. Contrast agents in medical X-rays use iodine.", useImage: IMG.ha, funFact: "Adding iodine to table salt has been called one of the most cost-effective public health interventions in history!" },
    54: { discoverer: "William Ramsay & Morris Travers", discovererBio: "Ramsay and Travers, the noble gas discovery duo, found xenon in 1898 — their last noble gas discovery.", experiment: "In 1898, after discovering neon and krypton, they continued fractionally distilling liquid air. In the heaviest fraction, they found xenon — 'the stranger' from Greek 'xenos.' It was the rarest atmospheric noble gas.", detailedUse: "Xenon fills high-intensity car headlights (xenon HID lamps). Ion thrusters on spacecraft (NASA's Dawn probe) use xenon for propulsion. Xenon is used as a general anaesthetic in surgery in some countries.", useImage: IMG.ng, funFact: "Xenon was the first noble gas shown to form chemical compounds — previously they were thought to be completely unreactive!" },
    55: { discoverer: "Robert Bunsen & Gustav Kirchhoff", discovererBio: "The same spectroscopy pioneers who discovered rubidium found caesium just months later in 1860.", experiment: "In 1860, Bunsen and Kirchhoff examined mineral spring water spectroscopically and found two bright blue lines matching no known element. They named it 'caesium' from Latin 'caesius' (sky blue).", detailedUse: "Caesium atomic clocks define the second (9,192,631,770 oscillations of Cs-133). GPS, internet, and global finance all depend on caesium timing. Caesium formate drilling fluid is used in oil exploration.", useImage: IMG.am, funFact: "The official definition of one second is based on caesium atoms — making it the most precisely measured unit!" },
    56: { discoverer: "Carl Wilhelm Scheele", discovererBio: "Swedish chemist (1742–1786) who identified barite (BaSO₄) as containing a new element in 1774.", experiment: "Scheele recognised that barite contained a new 'earth' (oxide) in 1774. Humphry Davy isolated barium metal by electrolysis in 1808, naming it from Greek 'barys' (heavy) due to barite's density.", detailedUse: "Barium sulfate 'milkshakes' are drunk before X-rays to highlight the digestive tract (barium is opaque to X-rays). Barium compounds create green fireworks. Barium titanate is in ceramic capacitors.", useImage: IMG.ae, funFact: "You can safely drink barium sulfate for medical imaging because it's completely insoluble — your body can't absorb it!" },
    57: { discoverer: "Carl Gustaf Mosander", discovererBio: "Swedish chemist (1797–1858), a student of Berzelius who discovered three rare earth elements.", experiment: "In 1839, Mosander partially decomposed cerium oxide and found a new element hiding within it. He named it 'lanthanum' from Greek 'lanthanein' (to lie hidden), because it had been concealed inside cerium compounds.", detailedUse: "Lanthanum makes camera and telescope lenses with excellent optical clarity. Lighter flints are made from mischmetall (an alloy containing lanthanum). Lanthanum carbonate treats kidney patients.", useImage: IMG.la, funFact: "Lanthanum hid inside cerium for decades before Mosander uncovered it — living up to its name 'the hidden one'!" },
    58: { discoverer: "Jöns Jacob Berzelius & Wilhelm Hisinger", discovererBio: "Berzelius (Swedish, 1779–1848) and Hisinger (Swedish, 1766–1852) found cerium in a heavy reddish mineral.", experiment: "In 1803, they found a new oxide in the mineral cerite from Sweden. Martin Klaproth independently discovered it the same year. Named after the asteroid Ceres, which had been discovered just two years earlier.", detailedUse: "Cerium oxide polishes glass (car windshields, mirrors). Self-cleaning oven coatings use cerium. Catalytic converters contain cerium. Cerium is the most abundant of all rare earth elements.", useImage: IMG.la, funFact: "Cerium is actually more common in Earth's crust than copper — 'rare earth' is a very misleading name!" },
    59: { discoverer: "Carl Auer von Welsbach", discovererBio: "Austrian chemist (1858–1929) who invented the gas mantle for lighting and the metal filament light bulb.", experiment: "In 1885, von Welsbach separated 'didymium' (thought to be one element) into two distinct elements — praseodymium (green twin) and neodymium (new twin), using fractional crystallisation of their salts.", detailedUse: "Praseodymium makes green glass for welder's goggles. Pr-Nd magnets are used in aircraft engines. Praseodymium dopes zirconia to create vivid yellow ceramic pigments. Used in fibre optic amplifiers.", useImage: IMG.la, funFact: "Praseodymium means 'green twin' in Greek — it was born when didymium was split into twin elements!" },
    60: { discoverer: "Carl Auer von Welsbach", discovererBio: "Austrian chemist (1858–1929) who split didymium into praseodymium and neodymium simultaneously.", experiment: "In 1885, von Welsbach performed repeated fractional crystallisation of didymium salts. He obtained two fractions with different absorption spectra — the rose-coloured fraction was neodymium ('new twin').", detailedUse: "Neodymium magnets (Nd₂Fe₁₄B) are the strongest permanent magnets known. They're in every hard drive, headphone, electric motor, and wind turbine generator. Neodymium-doped YAG lasers cut metal.", useImage: IMG.la, funFact: "A small neodymium magnet can lift 1,000 times its own weight — a 1-gram magnet lifts 1 kg!" },
    61: { discoverer: "Jacob Marinsky, Lawrence Glendenin & Charles Coryell", discovererBio: "American scientists who identified promethium in nuclear reactor products at Oak Ridge in 1945.", experiment: "In 1945, they analysed uranium fission products using ion exchange chromatography and identified element 61. Named after Prometheus, who stole fire from the gods — fitting for an element born from nuclear fire.", detailedUse: "Promethium powers long-life nuclear batteries for pacemakers and spacecraft instruments. Promethium-147 luminous paint was used in watches. It generates electricity from radioactive decay.", useImage: IMG.la, funFact: "Promethium is the only rare earth element with no stable isotopes — every atom is radioactive!" },
    62: { discoverer: "Paul Emile Lecoq de Boisbaudran", discovererBio: "French chemist (1838–1912) who found samarium spectroscopically in the mineral samarskite.", experiment: "In 1879, de Boisbaudran examined the mineral samarskite with a spectroscope and found new absorption lines. He isolated an oxide of a new element — samarium, named after the mineral (itself named after Russian officer Samarsky).", detailedUse: "Samarium-cobalt magnets work at extreme temperatures (inside jet engines). Samarium-153 treats bone cancer pain. Samarium oxide catalyses chemical reactions. SmCo magnets don't corrode like neodymium.", useImage: IMG.la, funFact: "Samarium is named after Colonel Samarsky-Bykhovets — the first person ever to have an element named after them!" },
    63: { discoverer: "Eugène-Anatole Demarçay", discovererBio: "French chemist (1852–1903) who isolated europium through meticulous fractional crystallisation.", experiment: "In 1901, Demarçay suspected that samarium preparations contained another element. Through painstaking fractional crystallisation, he obtained a pure new element — europium, named after the continent of Europe.", detailedUse: "Europium creates the red colour in LED screens, TVs, and fluorescent lights. Euro banknotes contain europium-based phosphors that glow red under UV light for anti-counterfeiting security.", useImage: IMG.la, funFact: "Check a Euro banknote under UV light — it glows red because of europium! It's an anti-counterfeit measure." },
    64: { discoverer: "Jean Charles Galissard de Marignac", discovererBio: "Swiss chemist (1817–1894) who found gadolinium in the mineral samarskite in 1880.", experiment: "In 1880, Marignac analysed samarskite and found a new oxide with different spectral properties from samarium. Named after Finnish chemist Johan Gadolin — the founder of rare earth chemistry.", detailedUse: "Gadolinium contrast agents make MRI scans clearer (it's paramagnetic). Gadolinium is used in nuclear reactor control rods. Gadolinium-based compounds are being explored for magnetic refrigeration.", useImage: IMG.la, funFact: "Gadolinium has the strongest paramagnetism of any element — it's attracted to magnets at room temperature!" },
    65: { discoverer: "Carl Gustaf Mosander", discovererBio: "Swedish chemist (1797–1858) who extracted terbium from yttria in 1843.", experiment: "In 1843, Mosander further separated yttria (yttrium oxide) and obtained two new oxides. One was rose-coloured (erbium) and the other was yellowish (terbium). Both named after the village of Ytterby, Sweden.", detailedUse: "Terbium creates green phosphors in flat-panel displays, LEDs, and fluorescent lamps. Terbium-iron alloys (Terfenol-D) change shape in magnetic fields — used in sonar systems and actuators.", useImage: IMG.la, funFact: "Terbium is one of four elements named after Ytterby — this tiny Swedish village has more elements named after it than any other place!" },
    66: { discoverer: "Paul Emile Lecoq de Boisbaudran", discovererBio: "French chemist (1838–1912) who isolated dysprosium from holmium oxide in 1886.", experiment: "In 1886, de Boisbaudran performed over 30 precipitations to separate dysprosium from holmium oxide. He named it from Greek 'dysprositos' meaning 'hard to get at' — reflecting the difficulty of isolation!", detailedUse: "Dysprosium is essential for high-performance magnets in wind turbines and EV motors (DyNdFeB magnets resist demagnetisation at high temperatures). Also used in nuclear reactor control rods.", useImage: IMG.la, funFact: "Dysprosium literally means 'hard to get at' — and today it's critically important for green energy technology!" },
    67: { discoverer: "Jacques-Louis Soret & Marc Delafontaine", discovererBio: "Soret (Swiss, 1827–1890) observed holmium's spectral bands in 1878; Per Teodor Cleve isolated it in 1879.", experiment: "In 1878, Soret found unusual spectral absorption bands in erbium samples. Cleve separated it into two elements in 1879 and named one 'holmium' from Holmia (Latin for Stockholm).", detailedUse: "Holmium produces the strongest magnetic field of any element. Holmium-doped YAG lasers treat kidney stones and cancers. Holmium is used in nuclear reactor control and magnetic flux concentrators.", useImage: IMG.la, funFact: "Holmium has the strongest magnetic moment of any naturally occurring element — it's a magnetic superhero!" },
    68: { discoverer: "Carl Gustaf Mosander", discovererBio: "Swedish chemist (1797–1858) who first identified erbium in 1842.", experiment: "In 1842, Mosander split yttria into three fractions. One rose-coloured oxide contained a new element he named 'erbium' after Ytterby, Sweden — the same quarry that yielded yttrium and terbium.", detailedUse: "Erbium-doped fibre amplifiers (EDFAs) boost signals in fibre optic telecommunications — essentially powering the internet. Erbium lasers treat skin conditions and dental work. Pink glass uses erbium.", useImage: IMG.la, funFact: "Every time you use the internet, erbium amplifiers are boosting the signal in the fibre optic cables!" },
    69: { discoverer: "Per Teodor Cleve", discovererBio: "Swedish chemist (1840–1905) who discovered both thulium and holmium in 1879.", experiment: "In 1879, Cleve was processing erbium oxide when he found two previously unknown oxides. One was green (thulium), named after 'Thule,' the ancient name for Scandinavia.", detailedUse: "Thulium is used in portable X-ray machines (thulium-170 emits X-rays). Thulium-doped fibre lasers are used in surgery. Thulium is one of the least abundant rare earths but is vital for medical technology.", useImage: IMG.la, funFact: "Thulium is named after Thule — the ancient Greek name for the mysterious land at the edge of the world (Scandinavia)!" },
    70: { discoverer: "Jean Charles Galissard de Marignac", discovererBio: "Swiss chemist (1817–1894) who identified ytterbium in 'erbia' samples in 1878.", experiment: "In 1878, Marignac heated erbium oxide (erbia) and found it decomposed into two components. One he named 'ytterbia' — yet another element from the Ytterby quarry! The metal was first isolated in 1953.", detailedUse: "Ytterbium is used in precise stress gauges for earthquake monitoring and bridge safety testing. Ytterbium lasers are used in industrial cutting. Atomic clocks with ytterbium may replace caesium ones.", useImage: IMG.la, funFact: "Ytterbium atomic clocks are so precise they wouldn't lose a second in 10 billion years — the age of the universe!" },
    71: { discoverer: "Georges Urbain", discovererBio: "French chemist (1872–1938) who separated lutetium from ytterbium in 1907.", experiment: "In 1907, Urbain performed thousands of fractional crystallisations of ytterbium samples and isolated a new element. He named it 'lutecium' (later lutetium) after Lutetia, the Latin name for Paris.", detailedUse: "Lutetium is used in PET scan detectors (lutetium oxyorthosilicate crystals detect gamma rays). Lu-177 is used in targeted cancer therapy. Lutetium catalysts crack petroleum in oil refineries.", useImage: IMG.la, funFact: "Lutetium is the most expensive rare earth element — it costs about $10,000 per kilogram!" },
    72: { discoverer: "Dirk Coster & George de Hevesy", discovererBio: "Coster (Dutch, 1889–1950) and de Hevesy (Hungarian, 1885–1966, Nobel laureate) found hafnium in Copenhagen.", experiment: "In 1923, they used X-ray spectroscopy on Norwegian zircon samples and found element 72. Named 'hafnium' from Hafnia (Latin for Copenhagen, where the discovery was made). Bohr had predicted it would be found there.", detailedUse: "Hafnium absorbs neutrons excellently — it's used in nuclear reactor control rods. Hafnium alloys withstand extreme heat in jet engines. Intel uses hafnium oxide in modern CPU transistor gates.", useImage: IMG.tm, funFact: "Every modern Intel processor since 2007 contains a layer of hafnium oxide just a few atoms thick!" },
    73: { discoverer: "Anders Gustaf Ekeberg", discovererBio: "Swedish chemist (1767–1813) who named tantalum after King Tantalus of Greek mythology.", experiment: "In 1802, Ekeberg found a new oxide in Finnish and Swedish minerals. The element resisted dissolving in acid — like Tantalus who couldn't reach water in Hades, the oxide 'tantalised' chemists by resisting acid attack.", detailedUse: "Tantalum capacitors are in every phone, laptop, and game console. Tantalum is biocompatible — used in surgical implants and hearing aid components. It's also used in jet engine turbine blades.", useImage: IMG.tm, funFact: "Your smartphone contains about 40 mg of tantalum — mining it has unfortunately fuelled conflicts in central Africa." },
    74: { discoverer: "Juan José & Fausto Elhuyar", discovererBio: "Spanish brothers (Juan José 1754–1796; Fausto 1755–1833) who isolated tungsten from wolframite ore.", experiment: "In 1783, the Elhuyar brothers reduced tungstic acid (from wolframite) with charcoal and obtained a metalite — tungsten. Named from Swedish 'tung sten' meaning 'heavy stone.'", detailedUse: "Tungsten has the highest melting point of any metal (3,422°C). It makes light bulb filaments, drill bits, and armour-piercing ammunition. Tungsten carbide tools cut through steel. Darts use tungsten for density.", useImage: IMG.tm, funFact: "Tungsten has the highest melting point of any element — 3,422°C! You could pour molten iron on it and it wouldn't melt." },
    75: { discoverer: "Walter Noddack, Ida Tacke & Otto Berg", discovererBio: "Noddack (German, 1893–1960) and Tacke (German, 1896–1978, they later married) discovered rhenium spectroscopically.", experiment: "In 1925, they detected rhenium using X-ray spectroscopy in platinum ores and the mineral columbite. Named after the Rhine river (Rhenus in Latin). It was the last naturally occurring stable element to be discovered.", detailedUse: "Rhenium is critical for jet engine super-alloys (withstands extreme heat). It's used in catalysts for making lead-free gasoline. Rhenium-platinum alloys make thermocouples for measuring very high temperatures.", useImage: IMG.tm, funFact: "Rhenium is one of the rarest elements in Earth's crust — and one of the most expensive metals at ~$3,000/kg!" },
    76: { discoverer: "Smithson Tennant", discovererBio: "English chemist (1761–1815) who discovered both osmium and iridium in platinum ore residues.", experiment: "In 1803, Tennant dissolved crude platinum in aqua regia. A dark residue remained that others had ignored. He found it contained TWO new elements — osmium (named from Greek 'osme' = smell, due to its pungent oxide) and iridium.", detailedUse: "Osmium is the densest naturally occurring element (22.59 g/cm³). OsO₄ stains biological specimens for electron microscopy. Osmium alloys make ultra-durable pen tips, electrical contacts, and instrument pivots.", useImage: IMG.tm, funFact: "Osmium is the densest element — a basketball-sized sphere of osmium would weigh over 300 kg!" },
    77: { discoverer: "Smithson Tennant", discovererBio: "English chemist (1761–1815) who found iridium alongside osmium in 1803.", experiment: "In 1803, Tennant treated the dark residue from platinum ore with alkali and acids, separating two metals. The one with colourful salts was named 'iridium' from Iris, the Greek goddess of the rainbow.", detailedUse: "Iridium tips on spark plugs last longer in engines. The original kilogram standard in Paris was Pt-Ir alloy. Iridium is found in the K-T boundary layer — evidence of the asteroid that killed the dinosaurs.", useImage: IMG.tm, funFact: "The asteroid that killed the dinosaurs left a thin layer of iridium around the entire Earth — iridium is rare on Earth but common in meteorites!" },
    78: { discoverer: "Antonio de Ulloa", discovererBio: "Spanish naval officer (1716–1795) who first reported platinum in South American ores in 1735.", experiment: "In 1735, de Ulloa found silvery grains in Colombian gold mines that wouldn't melt in any furnace. Spanish conquistadors called it 'platina' (little silver) dismissively. It took decades before chemists recognised its value.", detailedUse: "Platinum catalytic converters clean car exhaust. It's used in cancer drugs (cisplatin), fibre optic production, pacemaker electrodes, and luxury jewellery. Platinum crucibles handle the most corrosive chemicals.", useImage: IMG.tm, funFact: "Platinum is 30 times rarer than gold — yet it was initially considered worthless 'little silver' by Spanish explorers!" },
    79: { discoverer: "Known since antiquity", discovererBio: "Gold has been treasured since at least 4600 BC. Ancient Egyptians considered it the flesh of the sun god Ra.", experiment: "Gold occurs naturally as nuggets in rivers. Ancient Egyptians extracted gold from quartz rock by crushing and washing. They discovered gold dissolves in aqua regia — a mixture of hydrochloric and nitric acid.", detailedUse: "Beyond jewellery, gold is critical in electronics (phone connectors), aerospace (astronaut visor coatings reflect harmful radiation), and medicine (gold nanoparticles in cancer treatment). Gold never corrodes.", useImage: IMG.Au, funFact: "All the gold ever mined in human history would fit into roughly three Olympic swimming pools!" },
    80: { discoverer: "Known since antiquity", discovererBio: "Mercury has been found in Egyptian tombs from 1500 BC. Ancient Chinese emperors drank mercury elixirs believing it granted immortality.", experiment: "Mercury occurs naturally as cinnabar (HgS). Ancient peoples heated cinnabar and condensed the mercury vapour. Alchemists called it 'quicksilver' because it's a liquid metal that moves like a living thing.", detailedUse: "Mercury filled thermometers for centuries (now being phased out). It's in fluorescent light bulbs, dental amalgam fillings (being replaced), and some industrial processes. Mercury compounds were used in hat-making.", useImage: IMG.tm, funFact: "The phrase 'mad as a hatter' came from hat-makers who went insane from mercury poisoning!" },
    81: { discoverer: "William Crookes", discovererBio: "English chemist and physicist (1832–1919) who observed thallium's green spectral line.", experiment: "In 1861, Crookes was examining selenium residues with a spectroscope and noticed a vivid green line. He named the element 'thallium' from Greek 'thallos' (green shoot). Claude-Auguste Lamy independently isolated it.", detailedUse: "Thallium compounds are used in semiconductor research, low-temperature thermometers, and medical cardiac imaging (thallium-201 stress tests). Historically used as rat poison (now banned in many countries).", useImage: IMG.pt, funFact: "Thallium is so toxic and untraceable that it was nicknamed 'the poisoner's poison' in crime novels!" },
    82: { discoverer: "Known since antiquity", discovererBio: "Lead has been used since 7000 BC. The Romans used it extensively for water pipes — 'plumbing' comes from Latin 'plumbum' (lead).", experiment: "Ancient Romans smelted lead from galena ore (PbS) in simple furnaces. They used lead for water pipes, wine sweetener (lead acetate), cosmetics, and paint. We now know this likely contributed to health problems.", detailedUse: "Lead-acid batteries start every car. Lead shields against radiation in hospitals and nuclear facilities. Lead solder joins electronics (being replaced by lead-free alternatives). Lead crystal glass sparkles beautifully.", useImage: IMG.pt, funFact: "The word 'plumbing' comes from Latin 'plumbum' (lead) — because Romans made water pipes from lead!" },
    83: { discoverer: "Claude François Geoffroy", discovererBio: "French chemist (1729–1753) who demonstrated that bismuth is a distinct element from lead and tin.", experiment: "In 1753, Geoffroy showed that bismuth was chemically different from lead. Earlier, it had been confused with tin and lead for centuries. Bismuth was one of the first metals to be recognised as a separate element.", detailedUse: "Bismuth subsalicylate is Pepto-Bismol (pink stomach medicine!). Bismuth replaces lead in shotgun pellets and fishing sinkers. Bismuth crystals form stunning rainbow-coloured hopper structures that look alien.", useImage: IMG.pt, funFact: "Bismuth crystals form naturally in amazing rainbow-coloured staircase structures — they look like sci-fi props!" },
    84: { discoverer: "Marie & Pierre Curie", discovererBio: "Marie Curie (Polish-French, 1867–1934) was the first woman to win a Nobel Prize and the only person to win two in different sciences.", experiment: "In 1898, the Curies processed tonnes of pitchblende ore by hand. They found a radioactive element 400× more active than uranium. Marie named it 'polonium' after her native Poland, then under foreign rule.", detailedUse: "Polonium-210 eliminates static electricity in industrial machinery. It's been used in spacecraft power supplies. Polonium is extremely radioactive and toxic — even microgram amounts can be lethal.", useImage: IMG.ac, funFact: "Marie Curie named polonium after Poland to draw attention to Poland's lack of independence — chemistry as political protest!" },
    85: { discoverer: "Dale Corson, Kenneth MacKenzie & Emilio Segrè", discovererBio: "American scientists at UC Berkeley who synthesised astatine in 1940 by bombarding bismuth with alpha particles.", experiment: "In 1940, they fired alpha particles at bismuth-209 in a cyclotron and produced astatine-211. Named from Greek 'astatos' (unstable). At any time, less than 1 gram of astatine exists naturally on Earth!", detailedUse: "Astatine-211 is being researched for targeted cancer therapy — it can deliver lethal radiation precisely to tumour cells while sparing healthy tissue. It's one of the rarest naturally occurring elements.", useImage: IMG.ha, funFact: "At any given moment, there's less than 28 grams of astatine in the entire Earth's crust — making it the rarest natural element!" },
    86: { discoverer: "Friedrich Ernst Dorn", discovererBio: "German physicist (1848–1916) who detected radon as a radioactive gas emitted by radium.", experiment: "In 1900, Dorn observed that radium emitted a radioactive gas. Rutherford had noted this 'emanation' too. The gas was eventually named 'radon' (from radium). It's the heaviest noble gas and completely radioactive.", detailedUse: "Radon testing kits detect dangerous radon levels in home basements (it seeps from rocks). Radon baths are used in some spas for pain relief (controversial). It was historically used in cancer treatment.", useImage: IMG.ng, funFact: "Radon is the second leading cause of lung cancer after smoking — it seeps invisibly into basements from underground rocks!" },
    87: { discoverer: "Marguerite Perey", discovererBio: "French physicist (1909–1975), student of Marie Curie. She was the first woman elected to the French Academy of Sciences.", experiment: "In 1939, Perey was purifying actinium-227 when she found an unexpected radioactive decay product. She identified it as element 87 — francium, named after France. She was the last person to discover a natural element.", detailedUse: "Francium is used only in basic atomic physics research. It's too radioactive and rare for practical applications. Less than 30 grams exist naturally at any time. It's the second rarest natural element after astatine.", useImage: IMG.am, funFact: "Francium is so radioactive that a lump would instantly vaporise itself from its own radioactive heat!" },
    88: { discoverer: "Marie & Pierre Curie", discovererBio: "The Curies (Marie: Polish-French, 1867–1934; Pierre: French, 1859–1906) discovered radium while researching radioactivity.", experiment: "In 1898, the Curies processed tonnes of pitchblende ore in a shed. After years of gruelling work, they isolated radium chloride. The element glowed blue-green in the dark! Marie won her second Nobel Prize for this.", detailedUse: "Radium was once used in luminous clock dials ('Radium Girls' painted them). Today, radium-223 treats bone metastases in cancer patients. Historically used in toothpaste and health tonics before dangers were known.", useImage: IMG.ae, funFact: "Marie Curie's notebooks are still so radioactive they must be stored in lead-lined boxes — and will remain so for 1,500+ years!" },
    89: { discoverer: "André-Louis Debierne", discovererBio: "French chemist (1874–1949), a friend and colleague of the Curies at the Sorbonne.", experiment: "In 1899, Debierne separated a new radioactive element from pitchblende residues that the Curies had already processed for radium. He named it 'actinium' from Greek 'aktinos' (beam/ray).", detailedUse: "Actinium-225 is a promising cancer treatment — it emits alpha particles that destroy tumour cells. Actinium is used as a neutron source for research. It gives the actinide series its name.", useImage: IMG.ac, funFact: "Actinium glows blue in the dark from its intense radioactivity — looking like supernatural light!" },
    90: { discoverer: "Jöns Jacob Berzelius", discovererBio: "Swedish chemist (1779–1848) who named thorium after Thor, the Norse god of thunder.", experiment: "In 1829, Berzelius analysed a mineral sent from Norway. He found a new radioactive oxide and named the element 'thorium' after Thor. Thorium's radioactive properties weren't discovered until 1898.", detailedUse: "Thorium may become a nuclear fuel (thorium reactors produce less waste). Gas mantle lanterns use thorium oxide for brilliant white light. Thorium is used in high-quality camera lenses and aerospace alloys.", useImage: IMG.ac, funFact: "India has the world's largest thorium reserves and is developing thorium nuclear reactors as future clean energy!" },
    91: { discoverer: "Kasimir Fajans & Oswald Helmuth Göhring", discovererBio: "Fajans (Polish-American, 1887–1975) and Göhring (German, 1889–unknown) found a short-lived isotope in 1913.", experiment: "In 1913, Fajans and Göhring identified a beta-emitting isotope while studying uranium's decay chain. Lise Meitner and Otto Hahn independently found a longer-lived isotope in 1913. Named 'protactinium' (before actinium) because it decays into actinium.", detailedUse: "Protactinium has no commercial uses. Pa-231 is used in ocean-floor dating research — its ratio to thorium-230 in sediments reveals ocean circulation patterns over millennia.", useImage: IMG.ac, funFact: "Protactinium is one of the rarest and most expensive naturally occurring elements — even more than gold!" },
    92: { discoverer: "Martin Heinrich Klaproth", discovererBio: "German chemist (1743–1817) who discovered uranium in pitchblende ore in 1789.", experiment: "In 1789, Klaproth dissolved pitchblende in acid and obtained a yellow compound of a new element. He named it 'uranium' after planet Uranus. Its radioactivity wasn't found until Becquerel's work in 1896.", detailedUse: "Uranium fuels nuclear power plants producing ~10% of world electricity with zero carbon. Depleted uranium makes dense armour-piercing shells. Uranium-lead dating determines the age of ancient rocks and meteorites.", useImage: IMG.ac, funFact: "A single uranium fuel pellet (the size of a gummy bear) produces as much energy as one ton of coal!" },
    93: { discoverer: "Edwin McMillan & Philip Abelson", discovererBio: "McMillan (American, 1907–1991, Nobel laureate) and Abelson (American, 1913–2004) created neptunium at Berkeley.", experiment: "In 1940, they bombarded uranium with neutrons in a cyclotron and found a new element. Named 'neptunium' after Neptune — the next planet after Uranus, just as neptunium follows uranium in the periodic table.", detailedUse: "Neptunium-237 is used in neutron detection instruments. It's produced as a byproduct in nuclear reactors. Neptunium is being studied as a potential nuclear fuel and for understanding nuclear waste behaviour.", useImage: IMG.ac, funFact: "Neptunium was named to follow uranium (Uranus) — and the next element, plutonium, follows the same planetary pattern!" },
    94: { discoverer: "Glenn Seaborg, Joseph Kennedy, Edwin McMillan & Arthur Wahl", discovererBio: "Seaborg (American, 1912–1999, Nobel laureate) led the team that discovered plutonium and nine other elements.", experiment: "In 1940-41, they bombarded uranium-238 with deuterons. The resulting neptunium decayed into a new element — plutonium, named after Pluto (the next planet). Initially classified top secret due to WWII atomic bomb potential.", detailedUse: "Plutonium-238 powers RTG batteries on space probes (Voyager, Curiosity, Perseverance). Pu-239 is used in nuclear weapons and some reactor fuels. Less than 5 kg of Pu-238 exists worldwide for space missions.", useImage: IMG.ac, funFact: "Voyager 1 and 2, now in interstellar space, are still powered by plutonium-238 batteries from the 1970s!" },
    95: { discoverer: "Glenn Seaborg, Ralph James, Leon Morgan & Albert Ghiorso", discovererBio: "Seaborg's team at the University of Chicago created americium in 1944 during the Manhattan Project.", experiment: "In 1944, they bombarded plutonium-239 with neutrons in a nuclear reactor. Named 'americium' after the Americas, paralleling europium's naming after Europe across the periodic table.", detailedUse: "Americium-241 is in essentially every household smoke detector — the tiny radioactive source ionises air to detect smoke particles. It's also used in industrial moisture and thickness gauges.", useImage: IMG.ac, funFact: "There's americium in your home right now — it's the radioactive source in smoke detectors that saves lives every day!" },
    96: { discoverer: "Glenn Seaborg, Ralph James & Albert Ghiorso", discovererBio: "Seaborg's team created curium at the University of Chicago in 1944.", experiment: "In 1944, they bombarded plutonium-239 with alpha particles in a cyclotron. Named 'curium' after Marie and Pierre Curie, honouring their pioneering radioactivity research.", detailedUse: "Curium-244 powers alpha particle X-ray spectrometers on Mars rovers (Spirit, Opportunity, Curiosity). It is used as a compact power source for space missions and in neutron moisture gauges for well-logging.", useImage: IMG.ac, funFact: "The Mars rovers Spirit, Opportunity, and Curiosity all used curium-244 to analyse Martian rocks and soil!" },
    97: { discoverer: "Stanley Thompson, Albert Ghiorso & Glenn Seaborg", discovererBio: "American nuclear chemists at UC Berkeley who created berkelium in 1949.", experiment: "In 1949, they bombarded americium-241 with alpha particles in the 60-inch cyclotron at Berkeley. Named 'berkelium' after the city of Berkeley, California, where it was created.", detailedUse: "Berkelium is produced in minute quantities in nuclear reactors. Its primary use is as target material for synthesising heavier elements. Berkelium-249 was used to create element 117 (tennessine).", useImage: IMG.ac, funFact: "Less than 1 gram of berkelium has ever been produced in total — it costs roughly $27 million per gram!" },
    98: { discoverer: "Stanley Thompson, Kenneth Street Jr., Albert Ghiorso & Glenn Seaborg", discovererBio: "American scientists at UC Berkeley who created californium in 1950.", experiment: "In 1950, they bombarded curium-242 with alpha particles. Named 'californium' after the state and university where it was made. Initially only a few atoms were produced at a time.", detailedUse: "Californium-252 emits neutrons used to detect gold, silver, and oil underground. It starts up nuclear reactors and treats certain cancers. Cf-252 scans shipping containers for explosives and contraband.", useImage: IMG.ac, funFact: "Californium-252 costs about $27 million per gram — it's one of the most expensive substances on Earth!" },
    99: { discoverer: "Albert Ghiorso & co-workers", discovererBio: "Ghiorso (American, 1915–2010) and colleagues found einsteinium in the debris of the first hydrogen bomb test.", experiment: "In 1952, einsteinium was found in the fallout of the 'Ivy Mike' thermonuclear test at Enewetak Atoll. Uranium in the device captured multiple neutrons then decayed. Named after Albert Einstein.", detailedUse: "Einsteinium is used purely for scientific research — studying the chemistry of heavy actinides. Only microscopic amounts have been produced. Es-253 has been used as a target to create heavier elements.", useImage: IMG.ac, funFact: "Einsteinium was discovered in the radioactive fallout of the first hydrogen bomb — ironic for an element named after the pacifist Einstein!" },
    100: { discoverer: "Albert Ghiorso & co-workers", discovererBio: "The same team that found einsteinium also discovered fermium in hydrogen bomb debris in 1952.", experiment: "Found alongside einsteinium in the 'Ivy Mike' nuclear test fallout. Identified through careful radiochemical analysis. Named after Enrico Fermi, who built the first nuclear reactor.", detailedUse: "Fermium has no commercial applications — only microgram quantities exist at any time. It's used in research to understand the nuclear structure and chemistry of the heaviest elements.", useImage: IMG.ac, funFact: "Fermium was kept secret for several years because it was discovered in classified nuclear weapon test debris!" },
    101: { discoverer: "Albert Ghiorso, Bernard Harvey, Gregory Choppin, Stanley Thompson & Glenn Seaborg", discovererBio: "The Berkeley team created mendelevium at the University of California in 1955.", experiment: "In 1955, they bombarded einsteinium-253 with alpha particles in a cyclotron — producing just 17 atoms! Named after Dmitri Mendeleev, who created the periodic table in 1869.", detailedUse: "Mendelevium has no practical applications outside research. Only tiny amounts have been produced. It's used to study chemical properties of superheavy elements through ultra-sensitive detection methods.", useImage: IMG.ac, funFact: "Mendelevium was identified from just 17 atoms — the smallest amount of a new element ever detected at the time!" },
    102: { discoverer: "Joint Institute for Nuclear Research (Dubna, Russia)", discovererBio: "A team at JINR led by Georgy Flyorov claimed discovery in 1966, though earlier claims were disputed.", experiment: "Multiple teams claimed discovery. The accepted date is 1966 at JINR, Dubna. Named after Alfred Nobel, inventor of dynamite and founder of the Nobel Prize.", detailedUse: "Nobelium has no practical applications. Only minute quantities are produced for research. Scientists study its chemistry to test whether relativistic effects change how heavy atoms behave chemically.", useImage: IMG.ac, funFact: "Nobelium is named after Alfred Nobel, but ironically Nobel might not have approved — he wanted science used for peace, not nuclear physics!" },
    103: { discoverer: "Albert Ghiorso & team at LBNL", discovererBio: "Ghiorso's team at Lawrence Berkeley National Laboratory created lawrencium in 1961.", experiment: "In 1961, they bombarded californium with boron-10 and boron-11 ions. Named after Ernest Orlando Lawrence, inventor of the cyclotron — the machine that made its creation possible.", detailedUse: "Lawrencium is the last of the actinides. Produced in microscopic quantities for research. Scientists study its electron configuration to understand how relativistic effects influence the heaviest atoms.", useImage: IMG.ac, funFact: "Lawrencium is named after the inventor of the cyclotron — fittingly, since cyclotrons are how we make these superheavy elements!" },
    104: { discoverer: "Joint Institute for Nuclear Research (Dubna)", discovererBio: "JINR scientists led by Georgy Flyorov created rutherfordium in 1964. Independently confirmed at Berkeley in 1969.", experiment: "In 1964, the JINR team bombarded plutonium with neon ions. Named after Ernest Rutherford, the New Zealand-born physicist who discovered the atomic nucleus.", detailedUse: "Rutherfordium has no practical uses. Only a few atoms are produced at a time using particle accelerators. Research focuses on understanding its chemical properties compared to lighter elements in its group.", useImage: IMG.tm, funFact: "Rutherfordium atoms only exist for about 1 hour before decaying — scientists must study them extremely quickly!" },
    105: { discoverer: "JINR (Dubna) & LBNL (Berkeley)", discovererBio: "Both labs claimed discovery in the 1960s-70s. Named 'dubnium' after Dubna, Russia, where JINR is located.", experiment: "JINR bombarded americium with neon ions (1968), while Berkeley bombarded californium with nitrogen ions (1970). After a naming controversy, IUPAC gave the name dubnium in 1997.", detailedUse: "Dubnium has no practical applications. Fewer than 100 atoms have been produced at once. Chemical studies show it behaves similarly to tantalum but with some unexpected deviations.", useImage: IMG.tm, funFact: "The naming of elements 104-109 caused a decades-long 'Transfermium Wars' between American, Russian, and German labs!" },
    106: { discoverer: "Albert Ghiorso & team at LBNL", discovererBio: "Ghiorso's Berkeley team created seaborgium in 1974 by bombarding californium with oxygen ions.", experiment: "In 1974, they fired oxygen-18 ions at californium-249. Named after Glenn Seaborg, who was still alive — the first time a living person had an element named after them (controversially).", detailedUse: "Seaborgium has no practical uses. Only a handful of atoms have been produced. Chemical experiments suggest it behaves like tungsten and molybdenum, but with relativistic modifications.", useImage: IMG.tm, funFact: "Glenn Seaborg was the only person alive who could write his address using element symbols: Sg, Lr, Bk, Am!" },
    107: { discoverer: "GSI Darmstadt (Germany)", discovererBio: "Peter Armbruster and Gottfried Münzenberg led the team at GSI Helmholtz Centre for Heavy Ion Research.", experiment: "In 1981, they bombarded bismuth-209 with chromium-54 ions in a heavy-ion accelerator. Only a few atoms were produced. Named after Niels Bohr, the Danish physicist who revolutionised atomic theory.", detailedUse: "Bohrium has no practical applications. Its chemical properties have been studied using only a few atoms at a time, confirming it belongs in group 7. It demonstrates relativistic chemistry effects.", useImage: IMG.tm, funFact: "Bohrium is named after Niels Bohr — whose model of the atom with electron orbits is what you see in our Bohr model viewer!" },
    108: { discoverer: "GSI Darmstadt (Germany)", discovererBio: "The same GSI team of Armbruster and Münzenberg created hassium in 1984.", experiment: "In 1984, they bombarded lead-208 with iron-58 ions. Named after the German state of Hesse (Latin: Hassia), where Darmstadt and GSI are located.", detailedUse: "Hassium has no practical uses. Remarkably, scientists have shown that hassium oxide (HsO₄) is volatile — just like osmium tetroxide — proving it belongs in group 8 as predicted.", useImage: IMG.tm, funFact: "Scientists studied hassium's chemistry using just a few atoms — confirming it behaves like osmium 126 places higher in the table!" },
    109: { discoverer: "GSI Darmstadt (Germany)", discovererBio: "Created by Armbruster and Münzenberg's team at GSI in 1982.", experiment: "In 1982, they bombarded bismuth-209 with iron-58 ions and detected a single atom of element 109. Named after Lise Meitner, the Austrian-Swedish physicist who co-discovered nuclear fission.", detailedUse: "Meitnerium has no practical applications. Only a few atoms have ever been produced. It serves as tribute to Lise Meitner, who was shamefully denied the Nobel Prize for her role in discovering nuclear fission.", useImage: IMG.tm, funFact: "Lise Meitner was nominated for the Nobel Prize 48 times but never won — naming element 109 after her corrected a historic injustice!" },
    110: { discoverer: "GSI Darmstadt (Germany)", discovererBio: "Created by Sigurd Hofmann's team at GSI in 1994.", experiment: "In 1994, they bombarded lead-208 with nickel-62 ions. Named 'darmstadtium' after the city of Darmstadt, Germany, where GSI is located.", detailedUse: "Darmstadtium has no practical uses. Only a few atoms have been created, each existing for milliseconds. Research focuses on whether relativistic effects make it behave differently from platinum.", useImage: IMG.tm, funFact: "Darmstadtium atoms exist for only about 10 seconds before decaying — blink and you'd miss an entire lifetime!" },
    111: { discoverer: "GSI Darmstadt (Germany)", discovererBio: "Created by Hofmann's team at GSI in 1994.", experiment: "In 1994, they fired nickel-64 ions at bismuth-209 and detected three atoms of element 111. Named after Wilhelm Röntgen, who discovered X-rays in nearby Würzburg in 1895.", detailedUse: "Roentgenium has no practical applications. Only about a dozen atoms have been created. Theoretical predictions suggest it might be the most electronegative metal, even more than gold.", useImage: IMG.tm, funFact: "Roentgenium honours Wilhelm Röntgen, whose accidental discovery of X-rays in 1895 revolutionised medicine forever!" },
    112: { discoverer: "GSI Darmstadt (Germany)", discovererBio: "Created by Hofmann's team at GSI in 1996.", experiment: "In 1996, they fused zinc-70 with lead-208. Named 'copernicium' after Nicolaus Copernicus, who proposed that Earth revolves around the Sun.", detailedUse: "Copernicium has no practical uses. Experiments suggest it may be a gas at room temperature — remarkably different from mercury above it. This would make it the heaviest known gas!", useImage: IMG.tm, funFact: "Copernicium might be a gas at room temperature — if true, it would be the only metal that's gaseous under normal conditions!" },
    113: { discoverer: "RIKEN (Japan)", discovererBio: "Kosuke Morita led the team at RIKEN institute in Saitama, Japan. Element 113 was the first discovered in Asia.", experiment: "In 2004, they bombarded bismuth-209 with zinc-70 ions and detected element 113. After years of confirming results, IUPAC recognised RIKEN's priority in 2015. Named 'nihonium' from Nihon (Japan).", detailedUse: "Nihonium has no practical applications. It was a milestone achievement for Asian science — the first element discovered in Asia and named after Japan.", useImage: IMG.pt, funFact: "Nihonium is the first element discovered in Asia — Japan celebrated with a special stamp and postcard series!" },
    114: { discoverer: "JINR (Dubna) & LLNL (Livermore)", discovererBio: "A Russian-American collaboration between JINR and Lawrence Livermore National Laboratory.", experiment: "In 1999, they bombarded plutonium-244 with calcium-48 ions. Named 'flerovium' after Georgy Flyorov, the physicist who founded the JINR superheavy element programme.", detailedUse: "Flerovium has no practical uses. It may be near the theorised 'island of stability' — a region where superheavy elements might have much longer half-lives than their neighbours.", useImage: IMG.pt, funFact: "Scientists hope flerovium is near the 'island of stability' — where superheavy elements might survive for years instead of milliseconds!" },
    115: { discoverer: "JINR (Dubna) & LLNL (Livermore)", discovererBio: "The same Russian-American collaboration that discovered flerovium.", experiment: "In 2003, they bombarded americium-243 with calcium-48 ions and produced four atoms of element 115. Named 'moscovium' after Moscow Oblast, the region where JINR is located.", detailedUse: "Moscovium has no practical applications. It exists for less than a second. Its creation confirmed the possibility of reaching the theorised island of stability for superheavy elements.", useImage: IMG.pt, funFact: "Moscovium was briefly famous in pop culture when UFO enthusiasts claimed 'element 115' powered alien spacecraft — it doesn't!" },
    116: { discoverer: "JINR (Dubna) & LLNL (Livermore)", discovererBio: "Another product of the Russian-American heavy element collaboration.", experiment: "In 2000, they bombarded curium-248 with calcium-48 ions. Named 'livermorium' after Livermore, California, home of Lawrence Livermore National Laboratory.", detailedUse: "Livermorium has no practical uses. Only a handful of atoms have been created. Its chemistry is expected to differ significantly from polonium due to strong relativistic effects.", useImage: IMG.pt, funFact: "Livermorium atoms decay in just 60 milliseconds — faster than a human blink (300ms)!" },
    117: { discoverer: "JINR, LLNL, ORNL & Vanderbilt University", discovererBio: "A multinational collaboration involving four major research institutions.", experiment: "In 2010, they bombarded berkelium-249 (shipped from Oak Ridge, Tennessee) with calcium-48 ions at JINR. Named 'tennessine' after Tennessee, home of Oak Ridge National Laboratory.", detailedUse: "Tennessine has no practical applications. It's one of the newest confirmed elements. Producing the berkelium target material took over a year of reactor irradiation at Oak Ridge.", useImage: IMG.ha, funFact: "Making tennessine required berkelium-249 from Oak Ridge — it took 2 years and cost millions of dollars to produce enough target material!" },
    118: { discoverer: "JINR (Dubna) & LLNL (Livermore)", discovererBio: "The Russian-American collaboration achieved the final element on the current periodic table in 2006.", experiment: "In 2006, they bombarded californium-249 with calcium-48 ions. Named 'oganesson' after Yuri Oganessian, the Russian nuclear physicist who led superheavy element research for decades.", detailedUse: "Oganesson is the last element on the periodic table. Only five atoms have been detected. Ironically, despite being a 'noble gas' on paper, calculations suggest it might be a solid — the heaviest solid noble gas.", useImage: IMG.ng, funFact: "Oganesson is one of only two elements named after living people (along with seaborgium) — Yuri Oganessian is still alive!" },
};

export function getElementHistory(atomicNumber: number): ElementHistory | undefined {
    return ELEMENT_HISTORY[atomicNumber];
}
